        "frontend/src/features/analytics/PriceChart.tsx:71-94:gridlines at [1, 0.75, 0.5, 0.25, 0]",
        "frontend/src/__tests__/VolumeChart.test.tsx:61-69:uses screen.getByText for exact label matching"
      ],
      "uncertainty": "None significant. The gridline values are hardcoded and the formatter is deterministic."
    }
  ],
  "assumption_checks": [
    {
